#include <bits/stdc++.h>
using namespace std;
const int maxn=20;
int n,sum,yh[maxn][maxn],ans[maxn],vis[maxn];
void dfs(int pos,int s) { //正在填第pos位置，和为s
	if(pos>n) {
		if(s==sum) {
			for(int i=1; i<=n; i++) {
				cout<<ans[i]<<" ";
			}
			exit(0);
		}
		return;
	}
	for(int i=1; i<=n; i++) {
		if(vis[i]) continue;
		vis[i]=1;
		ans[pos]=i;
		dfs(pos+1,s+yh[n][pos]*i);
		vis[i]=0;
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>sum;
	yh[1][1]=1;
	for(int i=2; i<=n; i++) {
		for(int j=1; j<=i; j++) {
			yh[i][j]=yh[i-1][j-1]+yh[i-1][j];
		}
	}
	dfs(1,0);
	return 0;
}
